# --- In-memory data store for demonstration ---
class DataStore:
    def __init__(self):
        self.users = {
            "user1": {
                "user_id": "user1",
                "username": "alice",
                "password_hash": self._hash_password("securepass1"),
                "email": "alice@example.com",
                "role": "admin"
            },
            "user2": {
                "user_id": "user2",
                "username": "bob",
                "password_hash": self._hash_password("securepass2"),
                "email": "bob@example.com",
                "role": "user"
            },
            "user3": {
                "user_id": "user3",
                "username": "charlie",
                "password_hash": self._hash_password("securepass3"),
                "email": "charlie@example.com",
                "role": "user"
            },
        }
        self.username_to_id = {u["username"]: uid for uid, u in self.users.items()}
        self.active_tokens = {}

    @staticmethod
    def _hash_password(password):
        salt = "static_salt_for_demo"
        return hashlib.sha256(f"{salt}{password}".encode()).hexdigest()

    def verify_password(self, username, password):
        user_id = self.username_to_id.get(username)
        if not user_id:
            return False
        return self.users[user_id]["password_hash"] == self._hash_password(password)

    def create_token(self, username):
        token = secrets.token_hex(32)
        self.active_tokens[token] = {
            "username": username,
            "created_at": time.time()
        }
        return token

    def validate_token(self, token):
        token_data = self.active_tokens.get(token)
        if not token_data:
            return None
        if time.time() - token_data["created_at"] > 3600:
            del self.active_tokens[token]
            return None
        return token_data["username"]

    def invalidate_token(self, token):
        if token in self.active_tokens:
            del self.active_tokens[token]
            return True
        return False


