# --- Service Implementations ---
class AuthServiceServicer(microservices_pb2_grpc.AuthServiceServicer):

    def Login(self, request, context):
        username = request.username
        password = request.password

        if not username or not password:
            return microservices_pb2.LoginResponse(
                success=False,
                token="",
                message="Username and password are required"
            )

        if data_store.verify_password(username, password):
            token = data_store.create_token(username)
            return microservices_pb2.LoginResponse(
                success=True,
                token=token,
                message="Login successful"
            )
        else:
            return microservices_pb2.LoginResponse(
                success=False,
                token="",
                message="Invalid credentials"
            )

    def ValidateToken(self, request, context):
        username = data_store.validate_token(request.token)
        if username:
            return microservices_pb2.TokenResponse(valid=True, username=username)
        return microservices_pb2.TokenResponse(valid=False, username="")

    def Logout(self, request, context):
        success = data_store.invalidate_token(request.token)
        return microservices_pb2.LogoutResponse(success=success)


class DataServiceServicer(microservices_pb2_grpc.DataServiceServicer):

    def _authenticate(self, token, context):
        username = data_store.validate_token(token)
        if not username:
            context.abort(grpc.StatusCode.UNAUTHENTICATED, "Invalid or expired token")
        return username

    def GetUser(self, request, context):
        self._authenticate(request.token, context)

        user = data_store.users.get(request.user_id)
        if not user:
            context.abort(grpc.StatusCode.NOT_FOUND, "User not found")

        return microservices_pb2.UserResponse(
            user_id=user["user_id"],
            username=user["username"],
            email=user["email"],
            role=user["role"]
        )

    def ListUsers(self, request, context):
        self._authenticate(request.token, context)

        page = max(1, request.page)
        page_size = min(max(1, request.page_size), 100)

        all_users = list(data_store.users.values())
        total_count = len(all_users)
        start = (page - 1) * page_size
        end = start + page_size
        page_users = all_users[start:end]

        user_responses = [
            microservices_pb2.UserResponse(
                user_id=u["user_id"],
                username=u["username"],
                email=u["email"],
                role=u["role"]
            )
            for u in page_users
        ]

        return microservices_pb2.ListUsersResponse(
            users=user_responses,
            total_count=total_count
        )

    def GetData(self, request, context):
        self._authenticate(request.token, context)

        import json
        sample_data = {
            "query": request.query,
            "results": [
                {"id": 1, "value": "sample_data_1"},
                {"id": 2, "value": "sample_data_2"},
            ],
            "timestamp": time.time()
        }

        return microservices_pb2.DataResponse(
            success=True,
            data=json.dumps(sample_data)
        )


# --- TLS Certificate Generation Utility ---
def generate_self_signed_certs(cert_dir="certs"):
    """Generate self-signed TLS certificates for development."""
    os.makedirs(cert_dir, exist_ok=True)
    key_path = os.path.join(cert_dir, "server.key")
    cert_path = os.path.join(cert_dir, "server.crt")

    if os.path.exists(key_path) and os.path.exists(cert_path):
        return key_path, cert_path

    try:
        from cryptography import x509
        from cryptography.x509.oid import NameOID
        from cryptography.hazmat.primitives import hashes, serialization
        from cryptography.hazmat.primitives.asymmetric import rsa
        import datetime

        key = rsa.generate_private_key(public_exponent=65537, key_size=2048)

        subject = issuer = x509.Name([
            x509.NameAttribute(NameOID.COUNTRY_NAME, "US"),
            x509.NameAttribute(NameOID.STATE_OR_PROVINCE_NAME, "Development"),
            x509.NameAttribute(NameOID.ORGANIZATION_NAME, "DevMicroservices"),
            x509.NameAttribute(NameOID.COMMON_NAME, "localhost"),
        ])

        cert = (
            x509.CertificateBuilder()
            .subject_name(subject)
            .issuer_name(issuer)
            .public_key(key.public_key())
            .serial_number(x509.random_serial_number())
            .not_valid_before(datetime.datetime.utcnow())
            .not_valid_after(datetime.datetime.utcnow() + datetime.timedelta(days=365))
            .add_extension(
                x509.SubjectAlternativeName([
                    x509.DNSName("localhost"),
                    x509.IPAddress(ipaddress.IPv4Address("127.0.0.1")),
                ]),
                critical=False,
            )
            .sign(key, hashes.SHA256())
        )

        with open(key_path, "wb") as f:
            f.write(key.private_bytes(
                encoding=serialization.Encoding.PEM,
                format=serialization.PrivateFormat.TraditionalOpenSSL,
                encryption_algorithm=serialization.NoEncryption(),
            ))

        with open(cert_path, "wb") as f:
            f.write(cert.public_bytes(serialization.Encoding.PEM))

        print(f"[TLS] Generated self-signed certificates in '{cert_dir}/'")
        return key_path, cert_path

    except ImportError:
        # Fallback: use openssl command line
        subprocess.run([
            "openssl", "req", "-x509", "-newkey", "rsa:2048",
            "-keyout", key_path, "-out", cert_path,
            "-days", "365", "-nodes",
            "-subj", "/CN=localhost/O=DevMicroservices"
        ], check=True)
        print(f"[TLS] Generated self-signed certificates via openssl in '{cert_dir}/'")
        return key_path, cert_path


