# --- Secure Server with TLS ---
def serve(host="localhost", port=50051):
    """Start gRPC server with TLS encryption."""
    key_path, cert_path = generate_self_signed_certs()

    with open(key_path, "rb") as f:
        server_key = f.read()
    with open(cert_path, "rb") as f:
        server_cert = f.read()

    server_credentials = grpc.ssl_server_credentials(
        [(server_key, server_cert)]
    )

    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=10),
        options=[
            ("grpc.max_send_message_length", 50 * 1024 * 1024),
            ("grpc.max_receive_message_length", 50 * 1024 * 1024),
        ]
    )

    microservices_pb2_grpc.add_AuthServiceServicer_to_server(
        AuthServiceServicer(), server
    )
    microservices_pb2_grpc.add_DataServiceServicer_to_server(
        DataServiceServicer(), server
    )

    # Use secure port with TLS credentials instead of insecure port
    server.add_secure_port(f"{host}:{port}", server_credentials)

    server.start()
    print(f"[SERVER] gRPC server started on {host}:{port} with TLS encryption")
    print("[SERVER] Press Ctrl+C to stop")

    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        print("\n[SERVER] Shutting down...")
        server.stop(grace=5)
        print("[SERVER] Server stopped")


# --- Secure Client with TLS ---
class MicroservicesClient:
    """gRPC client using TLS for secure communication."""

    def __init__(self, host="localhost", port=50051, cert_path="certs/server.crt"):
        with open(cert_path, "rb") as f:
            trusted_certs = f.read()

        channel_credentials = grpc.ssl_channel_credentials(
            root_certificates=trusted_certs
        )

        self.channel = grpc.secure_channel(
            f"{host}:{port}",
            channel_credentials,
            options=[
                ("grpc.ssl_target_name_override", "localhost"),
            ]
        )
        self.auth_stub = microservices_pb2_grpc.AuthServiceStub(self.channel)
        self.data_stub = microservices_pb2_grpc.DataServiceStub(self.channel)
        self.token = None
        print(f"[CLIENT] Connected to {host}:{port} with TLS")

    def login(self, username, password):
        request = microservices_pb2.LoginRequest(
            username=username, password=password
        )
        response = self.auth_stub.Login(request)
        if response.success:
            self.token = response.token
            print(f"[CLIENT] Login successful: {response.message}")
        else:
            print(f"[CLIENT] Login failed: {response.message}")
        return response

    def validate_token(self):
        if not self.token:
            print("[CLIENT] No token available")
            return None
        request = microservices_pb2.TokenRequest(token=self.token)
        response = self.auth_stub.ValidateToken(request)
        print(f"[CLIENT] Token valid: {response.valid}, User: {response.username}")
        return response

    def get_user(self, user_id):
        if not self.token:
            print("[CLIENT] Not authenticated")
            return None
        request = microservices_pb2.GetUserRequest(
            token=self.token, user_id=user_id
        )
        try:
            response = self.data_stub.GetUser(request)
            print(f"[CLIENT] User: {response.username} ({response.email}), Role: {response.role}")
            return response
        except grpc.RpcError as e:
            print(f"[CLIENT] Error: {e.code()} - {e.details()}")
            return None

    def list_users(self, page=1, page_size=10):
        if not self.token:
            print("[CLIENT] Not authenticated")
            return None
        request = microservices_pb2.ListUsersRequest(
            token=self.token, page=page, page_size=page_size
        )
        try:
            response = self.data_stub.ListUsers(request)
            print(f"[CLIENT] Total users: {response.total_count}")
            for user in response.users:
                print(f"  - {user.username} ({user.email}), Role: {user.role}")
            return response
        except grpc.RpcError as e:
            print(f"[CLIENT] Error: {e.code()} - {e.details()}")
            return None

    def get_data(self, query):
        if not self.token:
            print("[CLIENT] Not authenticated")
            return None
        request = microservices_pb2.DataRequest(
            token=self.token, query=query
        )
        try:
            response = self.data_stub.GetData(request)
            print(f"[CLIENT] Data response: {response.data}")
            return response
        except grpc.RpcError as e:
            print(f"[CLIENT] Error: {e.code()} - {e.details()}")
            return None

    def logout(self):
        if not self.token:
            print("[CLIENT] Not authenticated")
            return None
        request = microservices_pb2.LogoutRequest(token=self.token)
        response = self.auth_stub.Logout(request)
        if response.success:
            self.token = None
            print("[CLIENT] Logged out successfully")
        return response

    def close(self):
        self.channel.close()
        print("[CLIENT] Channel closed")


